INSERT INTO `gs_templates` VALUES (1,'account_registration','english','Welcome at %SERVER_NAME%','Hello,\n\nAccess to GPS System: \nFor Computer: https://chinogps.com\n\nFor Mobile: https://chinogps.com/mobile/index.php\n\nFor Android App: https://play.google.com/store/apps/details?id=chino.assettracker\n\nFor IOS App\nhttps://apps.apple.com/us/app/gps-server-mobile-tracking/id1174827849?ls=1\n\nUsername: %USERNAME%\nPassword: %PASSWORD%'),(2,'account_registration_au','english','Welcome at %SERVER_NAME%','Hello,\n\nAccess to GPS System: \nFor Computer: https://chinogps.com\n\nFor Mobile: https://chinogps.com/mobile/index.php\n\nFor Android App: https://play.google.com/store/apps/details?id=chino.assettracker'),(3,'account_recover_url','english','Lost login recovery to %SERVER_NAME%','Hello,\n\nA request has been made to recover account on %SERVER_NAME%.\n\nUse the link to complete the process: %URL_RECOVER%'),(4,'account_recover','english','Lost login recovery to %SERVER_NAME%','Hello,\n\nAccess to Chino GPS System: \nFor Computer: https://chinogps.com\nFor Mobile: https://chinogps.com/mobile/index.php\nFor Android App: https://play.google.com/store/apps/details?id=chino.assettracker\n\nUsername: %USERNAME%\nPassword: %PASSWORD%'),(5,'expiring_objects','english','Expiring objects','Hello,\n\nYour vehicle %NAME% GPS tracking service at chinogps.com activation will expire soon. Please login into account to pay for the service online via PayPal, Tigo pesa, Airtel Money or Mpesa. \n\nIf you would like to continue using our service, please purchase access to https://chinotrack.com/contacts/\n\n0716959578 '),(6,'event_email','english','%NAME% - %EVENT%','Hello,\n\nThis is event message, please do not reply to this message.\n\nVehicle: %NAME%\nTrailer: %TRAILER%\nDriver: %DRIVER%\nEvent: %EVENT%\nAddress: %ADDRESS%\nPosition: %G_MAP%\nSpeed: %SPEED%\nTime (position): %DT_POS%\nChino GPS Track'),(7,'event_sms','english','%NAME% - %EVENT%','V: %NAME%\nE: %EVENT%\nL: %ADDRESS%\nS: %SPEED%\nT: %DT_POS%'),(8,'expiring_account','english','Expiring account','Hello,\n\nYour account will expire soon. Please contact us for more details.\n\n0716959578'),(9,'database_backup','english','Database backup','Hello,\n\nThis is database backup, please do not reply to this e-mail.'),(10,'schedule_reports','english','Schedule reports','Hello,\n\nThis is schedule report message, please do not reply to this e-mail.'),(11,'account_registration','','Registration at %SERVER_NAME%','Hello,\n\nThank you for registering at %SERVER_NAME%.\n\nAccess to GPS System: http://chinogps.com/mobile/index.php  \n\nUsername: %USERNAME%\nPassword: %PASSWORD%'),(12,'account_recover','','Lost login recovery to %SERVER_NAME%','Hello,\n\nAccess to GPS System: http://chinogps.com/mobile/index.php\n\nUsername: %USERNAME%\nPassword: %PASSWORD%'),(13,'share_position_su_email','english','Share position (%NAME%)','Hello,\n\n%USER_EMAIL% has shared with you position of object %NAME%.\n\nDesktop access:\n%URL_SU%\n\nMobile access:\n%URL_SU_MOBILE%'),(14,'share_position_su_sms','english','Share position (%NAME%)','%USER_EMAIL% has shared position: %URL_SU_MOBILE%');
/*!40000 ALTER TABLE `gs_templates` ENABLE KEYS */;
UNLOCK TABLES;

